const closes = ctx.underlying.klines.map(k => k.close);
const rsiVal = ctx.helpers.rsi(closes, 14);
const ema12 = ctx.helpers.emaArray(closes, 12).at(-1);
const ema26 = ctx.helpers.emaArray(closes, 26).at(-1);
const momentum = Math.sign(ema12 - ema26);
const spot = ctx.underlying.price;

const logit = p => Math.log(p / (1 - p));
const sigmoid = x => 1 / (1 + Math.exp(-x));
const THRESHOLD = 0.04;

return ctx.markets.map(market => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "closed or expired" };
    }
    const mCtx = { market, underlying: ctx.underlying, timing: ctx.timing };
    const yes0 = ctx.helpers.bsOneTouch(mCtx);
    const isUpBarrier = market.strike > spot;
    const rsiShift = (rsiVal - 50) / 200;
    const momentumShift = momentum * 0.03;
    let shift = isUpBarrier ? (rsiShift + momentumShift) : -(rsiShift + momentumShift);
    const yes = sigmoid(logit(Math.min(Math.max(yes0, 1e-6), 1 - 1e-6)) + shift);
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, yes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];
    const result = {
      question: market.question,
      strike: market.strike,
      hoursToExpiry: Math.round(market.hoursToExpiry),
      marketPriceYes: market.outcomes[0].price,
      fairPriceYes: Math.round(yes * 1000) / 1000,
      bestEdge: Math.round(best.edge * 1000) / 1000,
      decision: best.edge >= THRESHOLD ? "buy" : "hold",
      side: best.edge >= THRESHOLD ? best.label : undefined,
    };
    return result;
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
